// Reverse IP + ICP filter — mirrors server/mock-data.js EXACTLY (same COMPANY_DB,
// NON_CORPORATE_PREFIXES, TARGET_INDUSTRIES) so the n8n path resolves identically
// to the relay's /webhook path. For each incoming beacon (item.json.body), resolve
// the IP to a company; drop non-corporate / out-of-ICP visits; otherwise emit one
// item { site, company, page, durationSec, ts } for the HTTP node to POST to /ingest.

const COMPANY_DB = [
  { ipPrefix: '52.95.', domain: 'stripe.com', name: 'Stripe', industry: 'Fintech', size: '1000-5000', country: 'United States', logo: 'https://logo.clearbit.com/stripe.com' },
  { ipPrefix: '104.16.', domain: 'shopify.com', name: 'Shopify', industry: 'E-commerce', size: '5000-10000', country: 'Canada', logo: 'https://logo.clearbit.com/shopify.com' },
  { ipPrefix: '13.107.', domain: 'datadoghq.com', name: 'Datadog', industry: 'SaaS', size: '1000-5000', country: 'United States', logo: 'https://logo.clearbit.com/datadoghq.com' },
  { ipPrefix: '151.101.', domain: 'hashicorp.com', name: 'HashiCorp', industry: 'Infrastructure', size: '1000-5000', country: 'United States', logo: 'https://logo.clearbit.com/hashicorp.com' },
  { ipPrefix: '35.190.', domain: 'atlassian.com', name: 'Atlassian', industry: 'Software', size: '5000-10000', country: 'Australia', logo: 'https://logo.clearbit.com/atlassian.com' },
  { ipPrefix: '192.30.', domain: 'github.com', name: 'GitHub', industry: 'Software', size: '1000-5000', country: 'United States', logo: 'https://logo.clearbit.com/github.com' },
  { ipPrefix: '3.101.', domain: 'plaid.com', name: 'Plaid', industry: 'Fintech', size: '500-1000', country: 'United States', logo: 'https://logo.clearbit.com/plaid.com' },
  { ipPrefix: '18.200.', domain: 'klarna.com', name: 'Klarna', industry: 'Fintech', size: '5000-10000', country: 'Sweden', logo: 'https://logo.clearbit.com/klarna.com' },
  { ipPrefix: '34.120.', domain: 'snowflake.com', name: 'Snowflake', industry: 'Infrastructure', size: '5000-10000', country: 'United States', logo: 'https://logo.clearbit.com/snowflake.com' },
  { ipPrefix: '20.190.', domain: 'twilio.com', name: 'Twilio', industry: 'SaaS', size: '5000-10000', country: 'United States', logo: 'https://logo.clearbit.com/twilio.com' },
  { ipPrefix: '162.247.', domain: 'bigcommerce.com', name: 'BigCommerce', industry: 'E-commerce', size: '500-1000', country: 'United States', logo: 'https://logo.clearbit.com/bigcommerce.com' },
  { ipPrefix: '199.232.', domain: 'segment.com', name: 'Segment', industry: 'SaaS', size: '500-1000', country: 'United States', logo: 'https://logo.clearbit.com/segment.com' },
  { ipPrefix: '23.235.', domain: 'netflix.com', name: 'Netflix', industry: 'Media', size: '10000+', country: 'United States', logo: 'https://logo.clearbit.com/netflix.com' },
  { ipPrefix: '208.78.', domain: 'riotgames.com', name: 'Riot Games', industry: 'Gaming', size: '1000-5000', country: 'United States', logo: 'https://logo.clearbit.com/riotgames.com' }
];

const NON_CORPORATE_PREFIXES = ['192.168.', '10.', '172.16.', '98.116.', '71.198.', '76.102.', '174.21.', '100.64.', '208.54.', '107.77.'];

const TARGET_INDUSTRIES = ['Fintech', 'E-commerce', 'SaaS', 'Software', 'Infrastructure'];

function reverseIpLookup(ip) {
  if (!ip) return null;
  if (NON_CORPORATE_PREFIXES.some((p) => ip.startsWith(p))) return null;
  return COMPANY_DB.find((c) => ip.startsWith(c.ipPrefix)) || null;
}

function isTargetIndustry(company) {
  return !!company && TARGET_INDUSTRIES.includes(company.industry);
}

const out = [];
for (const it of $input.all()) {
  const body = (it.json && it.json.body) || it.json || {};
  const { ip, site, page, durationSec, ts } = body;
  const company = reverseIpLookup(ip);
  if (!company) continue;            // non-corporate / unknown IP — dropped
  if (!isTargetIndustry(company)) continue; // out-of-ICP — dropped
  out.push({ json: { site, company, page, durationSec, ts } });
}
return out;
